using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;

/// <summary>
/// Tools available to the research agent: web search, note-taking, and note review.
/// </summary>
internal sealed partial class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _http = new();

    [Description("Search the web for information on a query. Returns relevant result titles and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36");

            var resp = await _http.SendAsync(request);
            resp.EnsureSuccessStatusCode();
            var html = await resp.Content.ReadAsStringAsync();

            var results = new StringBuilder();
            int count = 0;

            // Each result lives inside a <div class="result ..."> block.
            foreach (Match block in ResultBlockRegex().Matches(html))
            {
                if (count >= 8) break;

                var titleMatch = TitleRegex().Match(block.Value);
                var snippetMatch = SnippetRegex().Match(block.Value);

                var title = titleMatch.Success ? StripHtml(titleMatch.Groups[1].Value) : null;
                var snippet = snippetMatch.Success ? StripHtml(snippetMatch.Groups[1].Value) : null;

                if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(snippet))
                {
                    results.AppendLine($"**{title.Trim()}**");
                    results.AppendLine(snippet.Trim());
                    results.AppendLine();
                    count++;
                }
            }

            if (count == 0)
                return "No results found. Try rephrasing the query.";

            Console.WriteLine($"     ✅ Found {count} result(s)");
            return results.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Save an important research finding as a note for later reference.")]
    public string TakeNote(
        [Description("The content of the note to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Review all research notes saved so far.")]
    public string ReviewNotes()
    {
        Console.WriteLine($"  📋 Reviewing notes ({_notes.Count} total)");

        if (_notes.Count == 0)
            return "No notes yet. Use TakeNote to save findings.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== {_notes.Count} note(s) ===");
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"\n[{i + 1}] {_notes[i]}");
        }
        return sb.ToString();
    }

    // --- Helpers ---

    private static string StripHtml(string html)
    {
        var text = HtmlTagRegex().Replace(html, "");
        return System.Net.WebUtility.HtmlDecode(text).Trim();
    }

    [GeneratedRegex("""<div[^>]*class="[^"]*result[^"]*"[^>]*>.*?(?=<div[^>]*class="[^"]*result[^"]*"|$)""",
        RegexOptions.Singleline)]
    private static partial Regex ResultBlockRegex();

    [GeneratedRegex("""<a[^>]*class="result__a"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex TitleRegex();

    [GeneratedRegex("""class="result__snippet"[^>]*>(.*?)</""", RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("<.*?>")]
    private static partial Regex HtmlTagRegex();
}

